        vector<bool> ndp = dp;

        for (int i = 0; i <= a; i++) {

          if (dp[i]) {

            ndp[i % k] = true;

          }

        }

        dp = ndp;

      }

      for (int i = 0; i <= a; i++) {

        if (dp[i] && can(i, b, k - 1)) {

          return false;

        }

      }

      return true;

    };

    for (int k = 60; k >= 1; k--) {

